# s_prior_next[k'] = sum_k B_a[k', k] * s_belief[k]
# This is matrix-vector multiplication: s_prior_next = B_a @ s_belief
def predict_next_state(action, s_belief, B):
    s_prior_next = [0.0] * K
    for k_prime in range(K):
        for k in range(K):
            s_prior_next[k_prime] += B[action][k_prime][k] * s_belief[k]
    return s_prior_next

# G_epist = -sum_k s_prior_next[k] * sum_o A[o,k] * ln(A[o,k] / Q_o[o])
G_epist = 0.0
for k in range(K):
    if s_prior_next[k] > 1e-10:
        for o in range(N_obs):
            if A[o][k] > 1e-10 and Q_o[o] > 1e-10:
                G_epist -= s_prior_next[k] * A[o][k] * log(A[o][k] / Q_o[o])

# P(a) = exp(-beta_G * G(a)) / sum_j exp(-beta_G * G(j))
neg_G = {a: -G_values[a] for a in actions}
max_neg_G = max(neg_G.values())
exp_vals = {a: exp(beta_G * (v - max_neg_G)) for a, v in neg_G.items()}
total = sum(exp_vals.values())
probs = {a: e / total for a, e in exp_vals.items()}
selected = sample_from(probs)

# For observed observation o_obs and current posterior s_belief:
for k in range(K):
    A[o_obs][k] += alpha_B * s_belief[k] * (1.0 - A[o_obs][k])
# Renormalize columns of A so each column sums to 1
for k in range(K):
    col_sum = sum(A[o][k] for o in range(N_obs))
    if col_sum > 0:
        for o in range(N_obs):
            A[o][k] /= col_sum
